import React from "react"
import Layout from "../components/Layout"
import { graphql, Link } from "gatsby"

export default function Home({ data }) {
  const { title } = data.site.siteMetadata
  const { posts } = data.blog
  
  return (
    <Layout>
      <div>
        <h1>{title}</h1>
        <p>A minimalistic blog to catalogue the thoughts and beliefs of Ricky Dodd (<a href="https://www.github.com/rickydodd/">GitHub profile</a>). Any thought or belief posted on this blog is the thought or opinion of Ricky Dodd and does not represent the thoughts or beliefs of any other person (or entity), whether they associate with Ricky Dodd in a professional or private context.</p>
        
        <h2>Posts</h2>

        {posts.map(post => (
          <article key={post.id}>
            <Link to={post.fields.slug}>
              <h3>{post.frontmatter.title}</h3>
            </Link>
            <small>{post.frontmatter.author}, {post.frontmatter.date}</small>
            <p>{post.excerpt}</p>
          </article>
        ))}
      </div>
    </Layout>
  )
}

export const pageQuery = graphql`
  query IndexQuery {
    site {
      siteMetadata {
        title
        siteUrl
        description
      }
    }

    blog: allMarkdownRemark (sort: {fields: [frontmatter___date] order: DESC}) {
      posts: nodes {
        fields {
          slug
        }
        frontmatter {
          date(fromNow: true)
          title
          author
        }
        excerpt
        id
      }
    }
  }
`
